"""
MKT Christ Commentary — Joshua chapters 18–20
Run: python3 scripts/zc-christ-joshua-18-20.py

Key Christological decisions:
- Ch18: Shiloh tent = Christ as true tent of meeting (John 1:14)
- Ch18: Joshua's rebuke "how long will you delay?" = Heb 4:11 urgency
- Ch18: Levites' inheritance is YHWH himself = believers inherit God in Christ
- Ch18 v16: Valley of Ben-hinnom (Gehenna) = final judgment
- Ch18 v28: Jebus/Jerusalem still uncaptured = awaits David/Christ's enthronement
- Ch19 vv10-16: Zebulun territory = Isa 9:1/Matt 4:13-16; Christ's first ministry
- Ch19 v15: Bethlehem in Zebulun = place-name echo of messianic birthplace
- Ch19 vv49-50: Joshua receives his inheritance last = Christ the servant-leader (2 Cor 8:9)
- Ch20: Cities of refuge as type of Christ as asylum from the accuser (Heb 6:18)
- Ch20 v6: Confinement released at high priest's death = Heb 9:15 Christ's death releases
"""

import json, pathlib

ROOT = pathlib.Path('/home/domad/Documents/bible-study-website')

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOSHUA = {
  "18": {
    "1": '<p>A shadow: the tent of meeting set up at Shiloh — YHWH\'s dwelling placed among his people in the land — anticipates the great arc that runs from the tabernacle to the temple to the incarnation: "the Word became flesh and dwelt among us" (John 1:14). The word for "dwelt" in John 1:14 (<em>eskēnōsen</em>, "tabernacled") deliberately evokes the tent of meeting. What the tent accomplished partially and temporarily, Christ accomplishes fully and permanently.</p>',
    "2": '<p>A theme: seven tribes still without their inheritance — the distribution is partly complete, the rest yet to be claimed. The "already but not yet" pattern of the inheritance is built into the structure of the land distribution itself. The NT inherits this structure: believers are heirs of God (Rom 8:17), yet the full inheritance awaits the resurrection (1 Pet 1:4).</p>',
    "3": '<p>A direct forward pointer: "How long will you put off going in to claim the land the LORD your God has given you?" Joshua\'s rebuke against delay is taken up directly in Heb 4:11: "Let us, therefore, make every effort to enter that rest, so that no one will perish by following their example of disobedience." The land that remains unclaimed despite being given is the same theological pattern: the rest is real and available; the failure is the human unwillingness to press in and take it.</p>',
    "4": '<p>A theme: Joshua appoints surveyors to map the land before the lots are cast — the systematic preparation for distributing the inheritance. "I go to prepare a place for you" (John 14:2) — Christ prepares the inheritance for his people. The careful mapping of every portion of the land reflects the Father\'s care in knowing and preparing each person\'s place in the kingdom.</p>',
    "5": '<p>A theme: the land is divided into seven sections, with Judah anchoring the south and Joseph the north. The orderly distribution of territory according to tribal identity reflects the principle of 1 Cor 12:18: "God has placed the parts in the body, every one of them, just as he wanted them to be." The sovereign allocation of different portions to different parties is a structural analogy for how God distributes roles and gifts in the new covenant community.</p>',
    "6": '<p>A revelation of God: "I will cast lots for you before the LORD our God." The lot-casting at Shiloh, in the presence of YHWH, places divine sovereignty at the center of the distribution. "We were also chosen, having been predestined according to the plan of him who works out everything in conformity with the purpose of his will" (Eph 1:11). The inheritance is not negotiated but given — by sovereign divine allocation before the Lord.</p>',
    "7": '<p>A revelation of God: "The Levites have no share among you, for the priestly service of the LORD is their inheritance." YHWH himself is the Levites\' inheritance — not land, not material goods, but the divine presence mediated through priestly service. This anticipates the new covenant in which all believers are a "royal priesthood" (1 Pet 2:9) whose inheritance is God himself in Christ: "the LORD is my portion" (Ps 73:26; Lam 3:24). The priestly vocation of knowing God directly, without mediated land-inheritance, is the pattern for the whole people of God in the new covenant.</p>',
    "8": '<p>A theme: "Go and walk through the land, write up a description, and come back to me." The command to go, witness, and report anticipates the apostolic mission: "Go and make disciples of all nations... and surely I am with you always" (Matt 28:19-20). The surveyors who map the land for its future inhabitants prefigure the witnesses who describe the kingdom for those who will enter it.</p>',
    "9": '<p>A theme: the surveyors "mapped it town by town in seven sections, recorded in a document." The written record of the land serves as title deeds for the inheritance. The Scripture is the written record of the spiritual inheritance — "everything that was written in the past was written to teach us, so that through the endurance taught in the Scriptures and the encouragement they provide we might have hope" (Rom 15:4).</p>',
    "10": '<p>A revelation of God: "Joshua cast lots for them before the LORD in Shiloh. There Joshua distributed the land to the Israelites according to their allotted portions." The one who distributes the inheritance — Joshua/Jesus — stands before the LORD and gives each his portion. "To each one of us grace has been given as Christ apportioned it. This is why it says: \'When he ascended on high, he took many captives and gave gifts to his people\'" (Eph 4:7-8).</p>',
    "11": '<p>A shadow: Benjamin\'s lot falls between Judah and Joseph — the tribe that will contain Jerusalem sits geographically between the two dominant tribes. This anticipates the role of the Davidic-Solomonic capital as the meeting point of the whole nation. Christ, the son of David from Judah who is also the true Joseph-figure (the beloved son who saves his brothers), establishes his kingdom at the meeting point of all the tribes.</p>',
    "12": '<p>A theme: Benjamin\'s northern boundary begins at the Jordan and moves through Jericho — the conquest\'s opening theater. The inheritance is bounded by the sites of YHWH\'s great acts. The new covenant inheritance is similarly bounded and defined by what Christ accomplished: his incarnation, death, and resurrection are the boundary markers of the spiritual inheritance he distributes.</p>',
    "13": '<p>A theme: the boundary passes through Bethel — the place of Jacob\'s dream, where "the LORD stood above it" and promised "I will give you and your descendants the land on which you are lying" (Gen 28:13). Jacob\'s ladder vision pointed to Christ: "you will see \'heaven open and the angels of God ascending and descending on\' the Son of Man" (John 1:51). The border that runs through Bethel is the border of the land promised at the point where heaven and earth intersected.</p>',
    "14": '<p>A theme: the western boundary of Benjamin passes through Kiriath-jearim — where the ark of the covenant will rest for twenty years (1 Sam 7:1-2) before David brings it to Jerusalem. The ark\'s eventual movement along this very boundary from Kiriath-jearim to Jerusalem traces the path of YHWH\'s presence moving toward its permanent home in Christ — "the Word dwelt among us" (John 1:14).</p>',
    "15": '<p>A theme: the southern boundary runs from Kiriath-jearim to the spring of Nephtoah and toward Jerusalem. The boundary territory will become the most contested ground in biblical history — every empire passes through it. The place where the covenant people\'s inheritance is most contested is also where YHWH\'s definitive act of salvation (the cross) occurs. Jerusalem in its location on Benjamin\'s southern border with Judah is the contested ground that becomes the site of universal redemption.</p>',
    "16": '<p>A shadow: the boundary descends into the Valley of Ben-hinnom — the valley that will become the site of Molech worship and infant sacrifice under later Israelite kings (2 Kgs 23:10), and which Jesus uses as the image of final judgment (<em>Gehenna</em> = Greek transliteration of "Valley of Hinnom," Matt 5:22, 29-30). The boundary of Benjamin runs through the place that becomes the biblical image of final judgment — a geographical marker embedded in the tribal allotment that points forward to eschatological realities.</p>',
    "17": '<p>A theme: the Ascent of Adummim — "the Pass of the Red Things" — on the road from Jericho to Jerusalem, site of the Good Samaritan parable (Luke 10:30-37). The boundary passes through the road that Jesus will use as the setting for his parable of the neighbor who crosses every boundary to rescue the wounded. The geography of the allotment contains the setting for the clearest illustration of the second great commandment.</p>',
    "18": '<p>A theme: the boundary descends toward the Arabah — the deep rift valley that runs from the Sea of Galilee to the Dead Sea. John the Baptist would preach in this Arabah region (John 1:23 cites Isa 40:3: "a voice of one calling in the wilderness"), preparing the way for Christ. The geographical boundaries of Benjamin\'s inheritance trace the contours of the redemptive-historical landscape.</p>',
    "19": '<p>A theme: the boundary ends at the northern bay of the Dead Sea — the lowest point on earth, where the Jordan meets the salt sea. The Salt Sea in biblical imagery is the place of death, judgment, and the boundary of the cursed cities (Sodom/Gomorrah). The boundary of the inheritance touches the furthest edge of the land, including the place of judgment. Christ\'s inheritance includes the full extent of the fallen creation, to its lowest point.</p>',
    "20": '<p>A revelation of God: "The Jordan formed the eastern boundary" — the river of crossing, the baptism-site, the entrance to the promised land. John baptizes at the Jordan; Jesus is baptized there. The Jordan as eastern boundary of Benjamin\'s inheritance connects the land to the crossing motif that runs through the whole narrative of entering Christ\'s inheritance.</p>',
    "21": '<p>A theme: Jericho heads the list of Benjamin\'s cities — the city that fell first, by YHWH\'s direct act, without a blow from Israel\'s sword. Jericho is Benjamin\'s first city because it was YHWH\'s first gift. The inheritance begins with what YHWH accomplished, not with what Israel achieved.</p>',
    "22": '<p>A theme: Bethel in Benjamin\'s territory — the house of God, the site of Jacob\'s encounter with the divine. In the NT, Bethel\'s "house of God" is fulfilled in Christ himself (John 2:19-21) and then in the church as the dwelling of the Spirit (1 Cor 3:16). The city of Bethel in Benjamin\'s list is a placeholder for the theme of God\'s dwelling that finds its fulfillment in Christ and the new covenant community.</p>',
    "23": '<p>A theme: Ophrah appears in Benjamin\'s list. The name means "fawn" or "young deer" — a name associated with vulnerability and swiftness. The psalms use the deer image for the soul\'s thirst for God: "as the deer pants for streams of water, so my soul pants for you, my God" (Ps 42:1). The geography carries the vocabulary of covenant longing embedded in place names.</p>',
    "24": '<p>A theme: twelve towns in the first group, with their villages — the completeness of the tribal inheritance is expressed in the catalogue. "Your Father knows what you need before you ask him" (Matt 6:8). The detailed enumeration of every town and village reflects the divine attention to every aspect of the inheritance — nothing is left out, nothing is forgotten.</p>',
    "25": '<p>A theme: Gibeon heads the second list of Benjamin\'s towns — the Hivite city whose deceptive covenant with Israel was maintained despite its origin in fraud. Gibeon\'s place in Benjamin\'s inheritance as a legally incorporated Levitical city (21:17) illustrates that covenant inclusion, once secured, is permanent. Those whom Christ has received into covenant cannot be expelled merely because they came to him in need or through unexpected means.</p>',
    "26": '<p>A theme: Mizpah (watchtower) in Benjamin — the place of covenant assemblies, the site where Samuel gathered Israel (1 Sam 7:5), where Saul was chosen as king (1 Sam 10:17). Benjamin\'s territory contains the sites of major covenant-renewal moments in Israel\'s history, consistent with the tribe\'s role as the host of the holy city.</p>',
    "27": '<p>A theme: the city names continue — each representing communities that will be part of the covenant people\'s settlement. The specificity of the list reflects the covenant\'s specificity: YHWH\'s promises are not general or vague but addressed to particular people in particular places. "He calls his own sheep by name" (John 10:3).</p>',
    "28": '<p>A direct forward pointer: "Jebus — that is Jerusalem" appears in Benjamin\'s city list. But Jerusalem is not yet Israel\'s — the Jebusites still hold it (Josh 15:63). Its inclusion in the list as Benjamin\'s is a claim that precedes possession by centuries. David will finally capture it (2 Sam 5:6-9) and make it the city of the great King. Christ enters Jerusalem as its true king (Matt 21:5, citing Zech 9:9) — the moment the land distribution anticipated: the city claimed as "ours" long before the one who would truly reign there arrived.</p>'
  },
  "19": {
    "1": '<p>A theme: Simeon\'s lot falls within Judah\'s territory — the tribe is enclosed within the dominant southern tribe rather than having independent territory. Gen 49:7 prophesied that Simeon (with Levi) would be "scattered in Israel" because of the Shechem massacre. The lot-casting enacts this prophetic word: Simeon\'s inheritance is folded into Judah\'s. This is not failure but providence — the curse of scattering becomes the mechanism of covenant distribution throughout Judah.</p>',
    "2": '<p>A theme: Beersheba — "the well of the oath" — is the first city named in Simeon\'s allotment. It was the place of Abraham\'s covenant with Abimelech (Gen 21:31) and where YHWH appeared to Isaac (Gen 26:23-24) and Jacob (Gen 46:1-4). The southernmost city of the land ("from Dan to Beersheba") heads Simeon\'s list. The oath sealed at Beersheba frames the whole inheritance from south to north.</p>',
    "3": '<p>A theme: the Simeonite cities in the Negev — the dry southern desert region — represent the territory that requires the most faith to settle. The inheritance that appears least hospitable is still given, still promised. "Blessed are the meek, for they will inherit the earth" (Matt 5:5) — even the desert portions are inheritance.</p>',
    "4": '<p>A theme: Hormah — "devoted/destroyed" — is the place where Israel was defeated when they tried to enter Canaan without divine direction in Num 14:45, and where Israel later defeated Canaanites in Num 21:3. The history embedded in the place-name (defeat, then victory) traces the arc of obedience-then-disobedience-then-faith that runs through the wilderness narrative. Simeon inherits a place of both failure and redemption.</p>',
    "5": '<p>A theme: Ziklag — the city David will receive from Achish of Gath (1 Sam 27:6), used as his base during his fugitive years. Simeon\'s allotment includes a city that will become a Davidic place of refuge in the darkest period before David\'s enthronement. The inheritance of Simeon contains the place where the future king shelters — the marginal tribe hosting the marginal king-in-waiting.</p>',
    "6": '<p>A theme: thirteen cities for Simeon — a tribe without continuous territory, incorporated into Judah. The scattered tribe that cannot hold its own territory anticipates the NT principle of diaspora: "as aliens and strangers in the world" (1 Pet 2:11), the covenant people are not defined by continuous territorial control but by covenant identity. The Simeonite pattern is the Christian pattern.</p>',
    "7": '<p>A theme: four more cities added to Simeon\'s inheritance. The number of cities does not define the significance of the inheritance — Simeon\'s scattered cities matter as much in the covenant plan as Judah\'s extensive territory. "The parts that we think are less honorable we treat with special honor" (1 Cor 12:23) — the less-prominent tribes receive what they need, apportioned by the divine distributor.</p>',
    "8": '<p>A theme: "all the villages around these cities" — the inheritance extends beyond the named centers to include the unnamed surrounding areas. Christ\'s inheritance extends beyond the named and famous to include the unnamed and obscure. "He knows those who are his" (2 Tim 2:19) — including the villages, not just the cities.</p>',
    "9": '<p>A revelation of God: "The inheritance of the Simeonites was taken from the allotment of Judah, because Judah\'s share was more than they needed." The surplus of one tribe provides for the deficit of another — the principle of the new covenant community: "at the present time your plenty will supply what they need, so that in turn their plenty will supply what you need" (2 Cor 8:14). The redistribution of the land inheritance between Judah and Simeon is a type of the economic koinonia of the early church.</p>',
    "10": '<p>A shadow (forward pointer): the third lot falls for Zebulun, whose territory in the Galilee region will become the site of Christ\'s early ministry. Isaiah 9:1 names "the land of Zebulun and the land of Naphtali" as the location where "the people walking in darkness have seen a great light." Matthew 4:13-16 applies this to Jesus beginning his ministry in Galilee: "Leaving Nazareth, he went and lived in Capernaum, which was by the lake in the area of Zebulun and Naphtali." Zebulun\'s lot in Joshua 19 reserves the territory where the Light of the World will first shine.</p>',
    "11": '<p>A theme: Zebulun\'s boundary reaches Maralah and the coastal ridge of lower Galilee. The territory includes the trade routes of the Jezreel Valley — the via maris, the Way of the Sea that crossed from Egypt through Galilee to Mesopotamia. Isaiah 9:1 calls it "the Way of the Sea" — the very road where Christ\'s ministry would be visible to the nations passing through. Zebulun\'s inheritance is positioned at the intersection of the known world\'s major artery.</p>',
    "12": '<p>A theme: Daberath — a Zebulunite city on the slopes of Mount Tabor. Tabor is the probable location of the Transfiguration (Matt 17:1-2; cf. Luke 9:28), where Christ\'s glory was unveiled before the disciples. The mountain in Zebulun\'s territory becomes the site of the most direct revelation of Christ\'s divine nature in the Gospel narratives.</p>',
    "13": '<p>A theme: Gath-hepher — a city in Zebulun — is the birthplace of the prophet Jonah (2 Kgs 14:25). Jonah\'s mission, his death-and-resurrection three days in the fish, and his preaching to Gentiles in Nineveh make him the prophet whose experience most directly prefigures Christ\'s death and resurrection (Matt 12:39-40). The city that produces the type is embedded in the territory of the fulfillment.</p>',
    "14": '<p>A theme: Zebulun\'s boundary curves around through Hannathon. The winding boundary trace of Zebulun — the tribe associated with commerce and international traffic (Gen 49:13: "Zebulun will live by the seashore and become a haven for ships") — maps the territory from which the light would go out to the nations. Christ\'s early ministry in Zebulun-Naphtali was the beginning of the gospel\'s movement outward to all nations.</p>',
    "15": '<p>A shadow: Bethlehem in Zebulun appears in the city list — a different Bethlehem from the famous Judean town, but sharing the name "house of bread." Micah 5:2 would point to Bethlehem of Judah as the Messiah\'s birthplace; but this Galilean Bethlehem, in the tribe where Christ would minister, is a geographical echo. The "house of bread" theme — Christ as the bread of life (John 6:35), born in Bethlehem Ephrathah — resonates in the naming of this Galilean town.</p>',
    "16": '<p>A theme: Zebulun\'s full inheritance — twelve cities and their villages. The completeness of the lot for the tribe associated with Christ\'s ministry region is a reminder that the land was fully surveyed, fully allocated, fully given. Nothing of the inheritance is withheld: "He who did not spare his own Son, but gave him up for us all — how will he not also, along with him, graciously give us all things?" (Rom 8:32).</p>',
    "17": '<p>A shadow (forward pointer): the fourth lot falls for Issachar. The territory of Issachar covers the Jezreel Valley — one of the most fertile plains in Canaan, and the site of many decisive battles. Armageddon (Har Megiddo, the Hill of Megiddo) is in Issachar\'s territory — the place John uses as the image of the final eschatological battle (Rev 16:16). The inheritance of Issachar contains the eschatological battlefield where YHWH will win his final victory.</p>',
    "18": '<p>A theme: Jezreel — the great valley city — is in Issachar. Jezreel will become associated with Naboth\'s vineyard (1 Kgs 21), Jezebel\'s death (2 Kgs 9:30-37), and the name Hosea gives his son as a sign of judgment (Hos 1:4). The fertile valley of Issachar carries within it both the abundance of covenant blessing and the potential for the abuse that brings covenant judgment.</p>',
    "19": '<p>A theme: Shunem is in Issachar. The Shunammite woman of 2 Kgs 4:8-37, who built a room for Elisha and whose son was raised from the dead, lived here. The dead son restored to life in Issachar\'s territory is a type of the resurrection — a life-from-death miracle embedded in the geography of the tribal allotment.</p>',
    "20": '<p>A theme: the Issacharite cities continue — each representing a community in the Jezreel plain. "Your Father knows what you need" (Matt 6:8). The careful enumeration of cities reflects the divine attention to every community, every person in the inheritance. No city in Issachar\'s plain is unnamed or unmapped in YHWH\'s distribution.</p>',
    "21": '<p>A theme: Remeth, En-gannim — the city names in Issachar. En-gannim means "spring of gardens" — a life-giving water source in the fertile valley. Christ is the "spring of water welling up to eternal life" (John 4:14); the geography of Issachar\'s inheritance contains this water-of-life imagery in its place names.</p>',
    "22": '<p>A shadow: the boundary touches Tabor. Mount Tabor, the site of the probable Transfiguration, appears in both Zebulun\'s and Issachar\'s boundaries — it sits on the border between the two tribes. The mountain of Christ\'s revealed glory stands at the meeting point of two tribal inheritances, belonging to both, exclusively to neither. Christ\'s glory is not the possession of any single group.</p>',
    "23": '<p>A theme: "This is the inheritance of the tribe of the Issacharites according to their families." The completing formula is repeated for each tribe — the divine record of each community\'s inheritance is maintained. "I will not blot out the name of that person from the book of life, but will acknowledge that name before my Father and his angels" (Rev 3:5).</p>',
    "24": '<p>A theme: Asher\'s fifth lot — the northern coastal tribe. Asher\'s territory reaches from Carmel to the Phoenician coast, including the territory that will never be fully held against the Phoenician city-states. The coastal inheritance that extends to the Gentile world anticipates the gospel\'s movement outward: "beginning from Jerusalem" and reaching to the coastlands (Isa 42:4; Matt 12:21).</p>',
    "25": '<p>A theme: Helkath, Hali, Beten, Achshaph — the Asherite cities in lower Galilee. Asher\'s territory lies along the route from Galilee to the Mediterranean coast, the international corridor between east and west. Gen 49:20 says "Asher\'s food will be rich; he will provide delicacies fit for a king." The tribe associated with rich provision and royal delight is located along the route of international commerce where the wealth of nations passes.</p>',
    "26": '<p>A theme: "The territory reached Carmel to the west." Mount Carmel — the site of Elijah\'s contest with the prophets of Baal (1 Kgs 18) — is on Asher\'s western border. The mountain where YHWH dramatically demonstrated his power over the Baal cult, calling down fire, is embedded in the boundary of Asher\'s inheritance. The cosmic spiritual battle — YHWH vs. the false gods — is staked at the edge of the promised land.</p>',
    "27": '<p>A theme: the boundary extends toward Beth-dagon — "the house of Dagon," the Philistine grain god. The tribal territory of YHWH\'s covenant people butts up against the territory named for a pagan deity. The boundary marks not just geographic but theological distinction: YHWH\'s inheritance and Dagon\'s territory are adjacent, but the difference is absolute. Christ\'s kingdom advances into the world\'s territory — "in the world, but not of it" (John 17:16).</p>',
    "28": '<p>A theme: "as far as Great Sidon" — the boundary extends to the major Phoenician city-state. The inheritance reaches to the Gentile world but does not absorb it yet. Christ\'s ministry explicitly crosses into this territory: he goes to the region of Tyre and Sidon (Matt 15:21-28) where he heals the Syrophoenician woman\'s daughter — entering the territory that Asher\'s lot claimed but never fully occupied.</p>',
    "29": '<p>A theme: the boundary curves to the fortified city of Tyre. Tyre — the archetypal Gentile commercial power — stands at Asher\'s boundary. Its future judgment is the subject of Isaiah 23 and Ezekiel 26-28. The boundary of the promised land running along Tyre\'s wall is a permanent marker: the land claim of YHWH\'s people encompasses the world\'s greatest commercial powers, waiting for the day when "the wealth of the nations" flows into the city of God (Isa 60:5; Rev 21:24-26).</p>',
    "30": '<p>A theme: twenty-two Asherite cities with their villages. The completeness of the coastal inheritance — even the cities Israel will never effectively hold — is given in the distribution. The normative gift precedes actual possession. In the same way, every spiritual blessing is given "in Christ" (Eph 1:3) before it is experienced in practice.</p>',
    "31": '<p>A theme: the completing formula for Asher. Each tribe\'s inheritance is sealed by this formula as a permanent record. "Whoever believes in him shall not perish but have eternal life" (John 3:16) — the covenant record of each person\'s inclusion in Christ is as permanent as these land-distribution records.</p>',
    "32": '<p>A shadow (forward pointer): the sixth lot falls for Naphtali — the northern tribe whose territory, with Zebulun, is specifically named in Isa 9:1 as the place of the great light: "in the past he humbled the land of Zebulun and the land of Naphtali, but in the future he will honor Galilee of the nations, by the Way of the Sea, beyond the Jordan — the people walking in darkness have seen a great light" (Isa 9:1-2 / Matt 4:15-16). Naphtali\'s lot in Joshua 19 stakes the claim on the territory where Christ would begin his ministry.</p>',
    "33": '<p>A theme: Naphtali\'s boundary runs from Heleph to Lakkum. The territory is defined by the natural geography of upper Galilee — the Huleh Valley, the foothills of Lebanon, the approaches to Hermon. Christ\'s ministry will extend through this northern territory; the Transfiguration on Hermon (some locate it here rather than Tabor) and the Caesarea Philippi confession (Matt 16:13-16) occur in Naphtali\'s northern reaches.</p>',
    "34": '<p>A theme: "touching Zebulun on the south, Asher on the west, and Judah at the Jordan toward the east." Naphtali borders on three other tribes, including the distant Judah "at the Jordan." This unusual cross-tribal boundary touch is a cartographic puzzle; but it signals that Naphtali — the northernmost territory — is nevertheless connected to Judah, the tribe of the Messiah. Even at the geographic extremity of the land, the thread of covenant connection to the Davidic tribe is maintained.</p>',
    "35": '<p>A theme: the fortified cities of Naphtali include Chinnereth (=Kinnereth, the Sea of Galilee). The Sea of Galilee — where Christ walks on water, calms storms, calls his disciples, and appears after his resurrection — is embedded in Naphtali\'s inheritance. The sea of Christ\'s most dramatic miracles is the covenant inheritance of this northern tribe.</p>',
    "36": '<p>A theme: Hazor heads the Naphtali city list — the great city Joshua burned (11:11), Jabin\'s capital, now part of Naphtali\'s inheritance. The place of the most complete destruction becomes an inheritance city. What was cleared of opposition becomes a place of settlement. This is the pattern of redemption: "he gives the desolate land to her as her home" (Ps 68:6).</p>',
    "37": '<p>A theme: Kedesh in Naphtali — one of the cities of refuge (20:7), appearing here in the city list. The asylum city in Naphtali is the place where the manslayer can find safety from the blood avenger. Christ is present throughout the Naphtali territory, including at the place of asylum — accessible to those who flee for refuge from every corner of the northern territories.</p>',
    "38": '<p>A theme: nineteen cities and their villages for Naphtali. The specificity of the count — not a round number but an exact nineteen — reflects the actual survey data. The inheritance is not generalized but precisely measured. "Every hair of your head is counted" (Luke 12:7) — the same precision that characterizes the land distribution characterizes the Father\'s knowledge of his people.</p>',
    "39": '<p>A theme: the completing formula for Naphtali — the tribe of the light. The inheritance is sealed as a permanent record. "You are the light of the world" (Matt 5:14) — what began as the light shining in Zebulun and Naphtali (Isa 9:1) extends through Christ to his people, who carry the same light into the same darkness.</p>',
    "40": '<p>A theme: the seventh and final tribal lot falls for Dan. Seven is the number of completeness; the distribution is now complete. Dan\'s lot — the last — is not less significant for being last. "The last will be first, and the first will be last" (Matt 20:16). The order of the lots does not determine the value of the inheritance.</p>',
    "41": '<p>A theme: Zorah and Eshtaol in Dan\'s allotment — the hometown of Samson (Judg 13:2, 25). Samson, the judge who defeats the Philistines through his own death, is one of the most explicit types of Christ in Judges: he dies with the Philistines, pulling the temple down on them, destroying more in his death than in his life (Judg 16:30). His birthplace is in Dan\'s allotment, which the tribe will eventually fail to hold.</p>',
    "42": '<p>A theme: Shaalabbin ("place of foxes") and Aijalon (the Valley of Aijalon where the sun stood still, 10:12) are Danite towns. The valley of the miraculous long day — where YHWH\'s direct intervention gave Israel more time to complete the victory — is in Dan\'s territory. The place of temporal miracle sits in the tribe that will fail to use its time and territory effectively.</p>',
    "43": '<p>A theme: Timnah is in Dan\'s original allotment. Samson\'s wife was from Timnah (Judg 14:1); the Philistine connection that would characterize his life and death begins with this city in Dan\'s territory. The tribe\'s inheritance includes the points of contact and conflict with the Philistines — the enemy that will shape the next era of Israel\'s history.</p>',
    "44": '<p>A theme: Eltekeh and Gibbethon — also in Dan\'s allotment, but Dan will fail to hold them (these appear as Levitical cities in 21:23 from Dan, cities Dan assigned but never fully occupied). The gap between allotted inheritance and actual possession is the Dan story: the inheritance is given, but the tribe does not press in to take it. Heb 4:1 warns: "a promise of entering his rest still stands, let us be careful that none of you be found to have fallen short of it."</p>',
    "45": '<p>A theme: Jehud, Bene-berak ("sons of lightning"), Gath-rimmon — the Danite coastal cities approaching Joppa. Bene-berak echoes the Boanerges ("sons of thunder") name Jesus gives James and John (Mark 3:17). The place name in Dan\'s coastal allotment carries the same thunder/lightning root as the name of the disciples who will be reshaped from "sons of thunder" into beloved apostles.</p>',
    "46": '<p>A theme: Joppa is near Dan\'s boundary. Joppa (= modern Jaffa) will be where Peter has his vision of the clean and unclean animals (Acts 10:9-16), receiving the command to bring the gospel to Cornelius. The Gentile breakthrough begins at the port city near Dan\'s boundary — the tribe that failed to hold its coastal territory becomes, through the apostle Peter, the launching point for the gospel to reach the Gentile world.</p>',
    "47": '<p>A warning type: "when the Danites failed to hold their allotted territory, they went up and attacked Leshem... renaming it Dan." The tribe that could not hold its inheritance moved north and took a different city by force. The allotted inheritance was abandoned for an improvised substitute. This is the "Esau pattern" — trading the birthright for immediate gratification (Heb 12:16-17). The tribe that fails to enter and hold its God-given inheritance does not thereby escape the consequences; it loses what was given and substitutes something of its own choosing.</p>',
    "48": '<p>A theme: the completing formula for Dan — despite the partial failure, the tribal identity is preserved. The record of the inheritance is maintained even where the tribe faltered. God\'s covenant purposes are not defeated by human failure: "If we are faithless, he remains faithful, for he cannot disown himself" (2 Tim 2:13). The record of Dan\'s inheritance stands even though Dan did not fully take it.</p>',
    "49": '<p>A revelation of God: after all the tribes have received their inheritance, "the Israelites gave Joshua son of Nun an inheritance among them." The leader who distributed the whole land to others receives his portion last. This is the pattern of the servant-leader: "The greatest among you will be your servant" (Matt 23:11). Joshua holds his own inheritance in suspension until everyone else has received theirs — a type of Christ, "who, though he was rich, yet for your sake he became poor, so that you through his poverty might become rich" (2 Cor 8:9).</p>',
    "50": '<p>A type: "At the LORD\'s command they gave him the city he requested: Timnath-serah in the hill country of Ephraim. He rebuilt the city and settled there." The name Timnath-serah means "the portion that remains" or "the portion of the sun." Joshua builds and inhabits a city in his own inheritance — after giving the entire land to others. Christ, who "for the joy set before him endured the cross" (Heb 12:2), receives his inheritance after accomplishing the full distribution. The "portion that remains" for the servant-leader is the portion he receives after completing his mission for others.</p>',
    "51": '<p>A revelation of God: the comprehensive closing formula — "Eleazar the priest, Joshua son of Nun, and the heads of the ancestral tribes of Israel assigned by lot at Shiloh before the LORD, at the entrance to the tent of meeting. And so the distribution of the land was complete." The completion of the distribution "before the LORD, at the entrance to the tent of meeting" places the entire process under YHWH\'s authority and presence. The completed distribution is a covenant act, ratified before God. "It is finished" (John 19:30) — the work is complete, the inheritance is distributed, the distribution is ratified before the Father.</p>'
  },
  "20": {
    "1": '<p>A type: YHWH initiates the cities of refuge — their establishment is a divine command, not a human invention. Christ as the refuge of the soul was not a human religious concept; he was appointed by the Father: "God presented Christ as a sacrifice of atonement" (Rom 3:25). The cities of refuge are a divine institution of grace, pointing to the one who is graciously appointed as shelter from judgment.</p>',
    "2": '<p>A type: "Tell the Israelites: Set apart for yourselves the cities of refuge that I commanded through Moses." The cities are "set apart" (<em>qadesh</em>, the root of holiness/consecration) for a specific purpose — asylum. Christ is the "holy, blameless, pure, set apart from sinners" (Heb 7:26) high priest who is himself the city of refuge. The set-apart nature of the cities points to the holy one who is the asylum for sinners.</p>',
    "3": '<p>A type with direct NT application: "anyone who kills a person accidentally or unintentionally may flee there for sanctuary from the blood avenger." Heb 6:18 uses the city-of-refuge language directly: "we who have fled to take hold of the hope set before us may be greatly encouraged... we have this hope as an anchor for the soul." The "fleeing" to Christ for refuge from judgment is the conscious NT application of the city-of-refuge type. The blood avenger (<em>gōʾēl haddām</em>) who pursues the manslayer corresponds to the condemning function of the law and the accuser.</p>',
    "4": '<p>A type: "When the person flees to one of these cities and stops at the city gate, he must present his case to the elders of that city. They are to admit him." The city gate as the place of legal judgment — the elders who receive and hear the case — points to Christ as the one who stands at the gate: "I am the gate; whoever enters through me will be saved" (John 10:9). The accused does not approach a distant deity but presents himself at the accessible gate, where he is received by those authorized to grant asylum.</p>',
    "5": '<p>A type: "If the blood avenger pursues him, they must not surrender the accused, because he struck the person unintentionally and without prior malice." Christ\'s intercession ensures that the accusation cannot prevail against those who are in him: "Who will bring any charge against those whom God has chosen? It is God who justifies. Who then is the one who condemns? No one. Christ Jesus who died — more than that, who was raised to life — is at the right hand of God and is also interceding for us" (Rom 8:33-34). The city of refuge will not surrender its resident to the blood avenger; Christ will not surrender his people to the accuser.</p>',
    "6": '<p>A direct type with NT fulfillment: "He is to stay in that city until he has stood trial before the congregation, and until the death of the high priest who is serving at that time. After that, the manslayer may return." The death of the high priest releases the manslayer from confinement — a permanent amnesty through the priest\'s death. Heb 9:15 is the direct fulfillment: "Christ is the mediator of a new covenant, that those who are called may receive the promised eternal inheritance — now that he has died as a ransom to set them free from the sins committed under the first covenant." Christ\'s death as high priest releases all who were under the confinement of the law\'s condemnation. The manslayer\'s release is the shadow; the believer\'s justification through the death of the great High Priest is the substance.</p>',
    "7": '<p>A type: three cities of refuge on the west side of the Jordan: Kedesh (in Naphtali/Galilee), Shechem (in Ephraim/central), Hebron (in Judah/south). They are geographically distributed so that no one in any part of the western land is more than a day\'s journey from asylum. Christ is the asylum who is universally accessible: "everyone who calls on the name of the Lord will be saved" (Rom 10:13). No region, no distance, no background excludes a person from access to the refuge.</p>',
    "8": '<p>A type: three more cities on the east side of the Jordan: Bezer (Reuben), Ramoth-gilead (Gad), Golan (Manasseh). The six cities together — three west, three east — cover the entire inhabited land of Israel. The geographic completeness of the refuge system points to the universal availability of Christ: "there is no difference between Jew and Gentile — the same Lord is Lord of all and richly blesses all who call on him" (Rom 10:12). No one is geographically or ethnically excluded from access to the refuge.</p>',
    "9": '<p>A type: "These were the designated cities for all the Israelites and for the foreigners living among them." The cities of refuge are explicitly extended to the <em>gēr</em> — the sojourner, the non-Israelite resident. This inclusion of foreigners is the type of Christ\'s universal offer: "there is neither Jew nor Gentile, neither slave nor free, nor is there male and female, for you are all one in Christ Jesus" (Gal 3:28). The asylum from judgment is offered to insiders and outsiders alike — anyone who accidentally killed someone, anyone who stands under the condemnation of the law, may flee to the refuge and find safety until the death of the High Priest sets them free.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'joshua')
    merge_comm(existing, JOSHUA)
    save_comm('mkt-christ', 'joshua', existing)
    print('Joshua 18-20 mkt-christ written.')

if __name__ == '__main__':
    main()
